CREATE TABLE auth_event_log (
    id              uuid        NOT NULL DEFAULT gen_random_uuid(),
    event_type      text        NOT NULL,
    actor_id        text        NOT NULL,
    ip_address      inet,
    user_agent      text,
    metadata_json   jsonb,
    created_at      timestamptz NOT NULL DEFAULT now(),

    CONSTRAINT pk_auth_event_log PRIMARY KEY (id),
    CONSTRAINT ck_auth_event_type CHECK (event_type IN ('login', 'logout', 'signup', 'failed_login', 'password_reset'))
);

CREATE INDEX idx_auth_event_log_actor ON auth_event_log (actor_id, created_at DESC);
CREATE INDEX idx_auth_event_log_type ON auth_event_log (event_type, created_at DESC);
CREATE INDEX idx_auth_event_log_created ON auth_event_log (created_at DESC);
